    return regex.compile(f"({inner})")


def _token_char_offsets(token_bytes: Sequence[bytes]) -> list[int]:
    """Given the byte values of a sequence of tokens, returns the starting character offset
    of each token in the decoded text they concatenate to."""
    text_len = 0
    offsets = []
    for token in token_bytes:
        offsets.append(max(0, text_len - (0x80 <= token[0] < 0xC0)))
        text_len += sum(1 for c in token if not 0x80 <= c < 0xC0)
    return offsets

